# Detect password spray attacks using Entra ID sign-in logs
# Password spray: try the same password against many accounts
# Signs: many users, many failed attempts, short time window, same IP

import requests
from collections import defaultdict
from datetime import datetime, timedelta, timezone

def get_token():
    import requests as r
    resp = r.post(
        "https://login.microsoftonline.com/YOUR_TENANT_ID/oauth2/v2.0/token",
        data={
            "grant_type": "client_credentials",
            "client_id": "YOUR_APP_ID",
            "client_secret": "YOUR_SECRET",
            "scope": "https://graph.microsoft.com/.default",
        }
    )
    return resp.json()["access_token"]

def detect_password_spray(token, lookback_minutes=60, threshold_accounts=5):
    headers = {"Authorization": f"Bearer {token}"}
    since = (datetime.now(timezone.utc) - timedelta(minutes=lookback_minutes)).strftime("%Y-%m-%dT%H:%M:%SZ")

    resp = requests.get(
        "https://graph.microsoft.com/v1.0/auditLogs/signIns"
        f"?$filter=createdDateTime ge {since}"
        f" and status/errorCode ne 0"   # failed sign-ins only
        "&$select=createdDateTime,userPrincipalName,ipAddress,status,clientAppUsed"
        "&$top=999",
        headers={**headers, "ConsistencyLevel": "eventual"}
    )
    events = resp.json().get("value", [])

    # Group failures by IP address
    by_ip = defaultdict(set)
    for e in events:
        ip = e.get("ipAddress", "unknown")
        upn = e.get("userPrincipalName", "")
        if upn:
            by_ip[ip].add(upn)

    print(f"Analysing {len(events)} failed sign-ins in last {lookback_minutes} minutes")
    spray_candidates = {ip: users for ip, users in by_ip.items() if len(users) >= threshold_accounts}

    if spray_candidates:
        print(f"\n⚠ POSSIBLE PASSWORD SPRAY DETECTED:")
        for ip, users in sorted(spray_candidates.items(), key=lambda x: -len(x[1])):
            print(f"  IP {ip}: {len(users)} distinct accounts targeted")
            for u in list(users)[:5]:
                print(f"    - {u}")
    else:
        print("No spray pattern detected in this window.")

    return spray_candidates

token = get_token()
detect_password_spray(token, lookback_minutes=60, threshold_accounts=5)

# Block legacy authentication protocols that bypass MFA
# Legacy protocols (SMTP AUTH, IMAP, POP3, Basic Auth) don't support MFA
# They are a common attack vector for credential spray and stuffing

# Step 1: Identify legacy auth usage before blocking
import requests

def find_legacy_auth_users(token, days=30):
    headers = {"Authorization": f"Bearer {token}"}
    # Sign-in logs: filter for legacy client apps
    legacy_apps = [
        "Exchange ActiveSync",
        "IMAP4",
        "POP3",
        "SMTP",
        "Authenticated SMTP",
        "Exchange Web Services",
        "Autodiscover",
        "Offline Address Book",
        "Exchange Online PowerShell",
        "Other clients",
    ]

    resp = requests.get(
        "https://graph.microsoft.com/v1.0/auditLogs/signIns"
        "?$filter=clientAppUsed ne 'Browser' and clientAppUsed ne 'Mobile Apps and Desktop Clients'"
        "&$select=userPrincipalName,clientAppUsed,createdDateTime,ipAddress"
        "&$top=999",
        headers={**headers, "ConsistencyLevel": "eventual"}
    )

    legacy_users = {}
    for e in resp.json().get("value", []):
        app = e.get("clientAppUsed", "")
        upn = e.get("userPrincipalName", "")
        if app in legacy_apps and upn:
            legacy_users.setdefault(upn, set()).add(app)

    print(f"Users still using legacy auth ({len(legacy_users)}):")
    for upn, apps in sorted(legacy_users.items()):
        print(f"  {upn}: {', '.join(apps)}")
    return legacy_users

# Step 2: Create CA policy to block legacy auth (PowerShell)
# Use this ONLY after confirming no critical workloads depend on legacy auth
legacy_block_policy = {
    "displayName": "Block Legacy Authentication",
    "state": "enabled",
    "conditions": {
        "users": {
            "includeUsers": ["All"],
            "excludeGroups": ["EMERGENCY-ACCESS-GROUP-ID"]
        },
        "applications": {"includeApplications": ["All"]},
        "clientAppTypes": [
            "exchangeActiveSync",
            "other"       # catches IMAP, POP3, SMTP AUTH, Basic Auth
        ]
    },
    "grantControls": {
        "operator": "OR",
        "builtInControls": ["block"]
    }
}
